  chapter: 'Governance Loop · Survivable Correction · Arrival Architecture',
  linkedVars: ['xstar', 'phi'],
  linkedGlossary: [
    { label: 'I*', anchor: 'xstar' },
    { label: 'Φ(x)', anchor: 'phi' },
  ],
  relatedEssay: 'M087',
